uint32 timer_count(void)
{
	uint32 low;
	low = HAL_TIMER_GetCount(SYS_TIMER);
	return ~low;
}

void cpu_dcache_invalidate(void *addr, int size)
{
    uint32_t line_size = cpu_dcache_line_size();
    uint32_t start_addr = (uint32_t)addr;
    uint32_t end_addr = (uint32_t)addr + size + line_size - 1;

    asm volatile ("dmb" ::: "memory");
    start_addr &= ~(line_size - 1);
    end_addr &= ~(line_size - 1);
    while (start_addr < end_addr) {
        asm volatile ("mcr p15, 0, %0, c7, c6, 1" : : "r" (start_addr));  /* dcimvac */
        start_addr += line_size;
    }
    asm volatile ("dsb" ::: "memory");
}
